IO=0 sleep $UPDATE_INTERVAL else sudo gpioset gpiochip0 $GPIO=1 sleep $MEDIUM_DELAY sudo gpioset gpiochip0 $GPIO=0 sleep $MEDIUM_DELAY fi prev_tx=$curr_txdone 🎯 效果说明 流量状态 灯的行为 无流量 (&lt;100 bytes/s) 熄灭 少量流量 (100-5000) 慢闪（0.3秒间隔） 大量下载 (&gt;5000 bytes/s) 常亮 ⚙️ 安装运行 1️⃣ 保存脚本 1sudo nano /usr/local/bin/net-led.sh 粘贴上面的内容，保存退出（Ctrl+X，按 Y，回车）。 2️⃣ 给权限 1sudo chmod +x /usr/local/bin/net-led.sh 3️⃣ 测试 1sudo /usr/local/bin/net-led.sh 用手机连 WiFi 下载个文件，看灯是不是常亮了，按ctrl+c结束脚本。 设置成正确的开机自启方案 1️⃣ 把之前的脚本改成开机自启的 systemd 服务 先确保你的脚本是完整的（包含流量监控和闪烁逻辑），然后创建服务： 1sudo nano /etc/systemd/system/net-led.service 粘贴以下内容： 123456789101112[Unit]Description=Network Traffic LEDAfter=network.target multi-user.target[Service]Type=simpleExecStart=/usr/local/bin/net-led.shRestart=alwaysUser=root[Install]WantedBy=multi-user.target 2️⃣ 确保脚本有执行权限 1sudo chmod +x /usr/local/bin/net-led.sh 3️⃣ 启用并启动服务 12sudo systemctl enable net-led.servicesudo systemctl start net-led.service 4️⃣ 验证 1sudo systemctl status net-led.service 应该显示 active (running)，并且 GPIO 114 开始随流量闪烁。 在linux里查看板子型号 123cat /sys/firmware/devicetree/base/model# 返回例如&gt;Handsome OpenStick UFI003MB cups 常用命令 1234567891011121314151617181920212223# 查看打印机状态lpstat -p -d# 查看 CUPS 服务状态systemctl status cups# 查看 CUPS 版本cups-config --version# 查看所有可用命令ls /usr/bin/lp* /usr/sbin/lp*# 启动 CUPS 服务sudo systemctl start cups# 停止 CUPS 服务sudo systemctl stop cups# 重启 CUPS 服务sudo systemctl restart cups# 查看实时日志sudo tail -f /var/log/cups/error_log 命令 所属目录 主要功能 常用示例 lp /usr/bin 提交打印任务（最常用） lp -d 打印机名 文件.pdf lpr /usr/bin 另一种提交打印任务的命令 lpr -P 打印机名 文件.pdf lpq /usr/bin 查看打印队列（查看等待打印的任务） lpq -a（查看所有队列） lprm /usr/bin 取消打印任务 lprm 任务ID 或 lprm -（取消所有） lpstat /usr/bin 显示打印机状态和任务信息 lpstat -p -d（查看打印机） lpoptions /usr/bin 设置或查看打印选项 lpoptions -d 打印机名（设默认） lpunlock /usr/bin 解锁被锁定的打印机队列 lpunlock 打印机名 lpadmin /usr/sbin 添加、删除或配置打印机（需root） lpadmin -p 打印机名 -v 设备 lpinfo /usr/sbin 列出可用的打印机驱动和接口 lpinfo -v（查看可用连接） lpmove /usr/sbin 将任务从一个队列移到另一个 lpmove 任务ID 目标打印机 lpc /usr/sbin 控制打印机状态（启动/停止/启用） lpc status（查看状态） 在 lp 命令中，复杂的打印选项主要通过 -o 参数来指定。根据 CUPS 的官方文档，以下是常用的复杂打印选项 ： 页面布局与排版选项 选项 说明 示例值 -o number-up=N 每张纸上打印N页 2, 4, 6, 9, 16 -o page-border=border 每页添加边框 single（单线）, double（双线）, single-thick（粗单线） -o number-up-layout=layout 多页排列顺序 lrtb（从左到右，从上到下）, tblr（从上到下，从左到右）等 -o page-set=set 打印特定页面集 odd（奇数页）, even（偶数页）, booklet（小册子） -o outputorder=reverse 逆序打印 reverse -o mirror 镜像打印 （无值，直接使用） 双面与方向选项 选项 说明 示例值 -o sides=option 单面/双面设置 one-sided（单面）, two-sided-long-edge（双面长边）, two-sided-short-edge（双面短边） -o orientation-requested=N 打印方向 3（纵向）, 4（横向逆时针）, 5（横向顺时针）, 6（反向纵向） -o landscape 横向打印（简化版） （无值，直接使用） 纸张与质量选项 选项 说明 示例值 -o media=size 纸张大小 A4, Letter, Legal -o media=size,type 纸张大小和类型 A4,Transparency（A4透明胶片） -o media=source 纸盒来源 Upper（上纸盒）, Lower（下纸盒）, MultiPurpose（多功能纸盒） -o print-quality=N 打印质量 3（草稿）, 4（标准）, 5（最佳） 缩放与适配选项 选项 说明 示例值 -o fit-to-page 缩放以适合页面 （无值，直接使用） -o scaling=N 缩放百分比 75（缩放75%） 其他选项 选项 说明 示例值 -o collate=true 逐份打印 true 或 false -o job-sheets=name 添加封面页 standard, classified, confidential, topsecret -o page-ranges=page-list 指定页码范围 1-5, 1,3,5-7 -o job-priority=priority 任务优先级 1（最低）到 100（最高） 挂载硬盘盒 安装USB工具 12345678# 更新软件源sudo apt update# 安装 USB 基础工具sudo apt install usbutils usb-modeswitch# 安装文件系统支持（用于识别硬盘格式）sudo apt install ntfs-3g exfat-fuse exfat-utils 执行下面代码，不是所有都适用  &gt; usb_switch.sh &lt;&lt; &#x27;EOF&#x27;#!/bin/bash# USB 模式切换脚本 - 支持 host/gadget 切换并自动挂载/卸载硬盘# 颜色定义RED=&#x27;\033[0;31m&#x27;GREEN=&#x27;\033[0;32m&#x27;YELLOW=&#x27;\033[1;33m&#x27;BLUE=&#x27;\033[0;34m&#x27;NC=&#x27;\033[0m&#x27; # No Color# 配置MOUNT_POINT=&quot;/mnt/nas&quot;USB_ROLE_FILE=&quot;/sys/kernel/debug/usb/ci_hdrc.0/role&quot;LOG_FILE=&quot;/var/log/usb_switch.log&quot;# 显示使用方法show_usage() &#123; echo &quot;用法: $0 [host|gadget|status]&quot; echo &quot; host - 切换到主机模式（连接硬盘）并自动挂载&quot; echo &quot; gadget - 切换到设备模式（连接电脑）并自动卸载硬盘&quot; echo &quot; status - 显示当前状态&quot; exit 1&#125;# 日志函数log() &#123; echo -e &quot;$(date &#x27;+%Y-%m-%d %H:%M:%S&#x27;) - $1&quot; | tee -a &quot;$LOG_FILE&quot;&#125;# 检查是否 rootcheck_root() &#123; if [ &quot;$EUID&quot; -ne 0 ]; then echo -e &quot;$&#123;RED&#125;请用 sudo 运行此脚本$&#123;NC&#125;&quot; exit 1 fi&#125;# 获取当前模式get_current_mode() &#123; if [ -f &quot;$USB_ROLE_FILE&quot; ]; then cat &quot;$USB_ROLE_FILE&quot; 2&gt;/dev/null else echo &quot;unknown&quot; fi&#125;# 检查硬盘是否已挂载is_mounted() &#123; mount | grep -q &quot; $MOUNT_POINT &quot; return $?&#125;# 查找硬盘设备find_hdd() &#123; # 查找 sda 或 sdb 等设备 local hdd=$(lsblk -o NAME,TYPE | grep -E &quot;sd[a-z][0-9]&quot; | grep -v &quot;0B&quot; | head -1 | awk &#x27;&#123;print $1&#125;&#x27;) if [ -n &quot;$hdd&quot; ]; then echo &quot;/dev/$hdd&quot; else echo &quot;&quot; fi&#125;# 挂载硬盘mount_hdd() &#123; log &quot;$&#123;YELLOW&#125;尝试挂载硬盘...$&#123;NC&#125;&quot; # 创建挂载点 mkdir -p &quot;$MOUNT_POINT&quot; # 查找硬盘 HDD_DEV=$(find_hdd) if [ -z &quot;$HDD_DEV&quot; ]; then log &quot;$&#123;RED&#125;未找到硬盘设备$&#123;NC&#125;&quot; return 1 fi log &quot;找到硬盘设备: $HDD_DEV&quot; # 获取文件系统类型 FSTYPE=$(lsblk -o NAME,FSTYPE | grep &quot;$(basename $HDD_DEV)&quot; | awk &#x27;&#123;print $2&#125;&#x27;) log &quot;文件系统类型: $&#123;FSTYPE:-未知&#125;&quot; # 尝试挂载 if [ -n &quot;$FSTYPE&quot; ]; then case &quot;$FSTYPE&quot; in ntfs|NTFS) mount -t ntfs-3g &quot;$HDD_DEV&quot; &quot;$MOUNT_POINT&quot; 2&gt;/dev/null ;; exfat|EXFAT) mount -t exfat &quot;$HDD_DEV&quot; &quot;$MOUNT_POINT&quot; 2&gt;/dev/null ;; ext4|ext3|ext2) mount &quot;$HDD_DEV&quot; &quot;$MOUNT_POINT&quot; 2&gt;/dev/null ;; *) mount &quot;$HDD_DEV&quot; &quot;$MOUNT_POINT&quot; 2&gt;/dev/null ;; esac else # 尝试自动检测 mount &quot;$HDD_DEV&quot; &quot;$MOUNT_POINT&quot; 2&gt;/dev/null || \ mount -t ntfs-3g &quot;$HDD_DEV&quot; &quot;$MOUNT_POINT&quot; 2&gt;/dev/null || \ mount -t exfat &quot;$HDD_DEV&quot; &quot;$MOUNT_POINT&quot; 2&gt;/dev/null fi if [ $? -eq 0 ]; then log &quot;$&#123;GREEN&#125;硬盘挂载成功到 $MOUNT_POINT$&#123;NC&#125;&quot; # 设置权限 chmod 777 &quot;$MOUNT_POINT&quot; # 显示挂载信息 df -h &quot;$MOUNT_POINT&quot; | tail -1 return 0 else log &quot;$&#123;RED&#125;硬盘挂载失败$&#123;NC&#125;&quot; return 1 fi&#125;# 卸载硬盘umount_hdd() &#123; if is_mounted; then log &quot;$&#123;YELLOW&#125;卸载硬盘 $MOUNT_POINT...$&#123;NC&#125;&quot; umount &quot;$MOUNT_POINT&quot; if [ $? -eq 0 ]; then log &quot;$&#123;GREEN&#125;硬盘卸载成功$&#123;NC&#125;&quot; else log &quot;$&#123;RED&#125;硬盘卸载失败，可能正在被使用$&#123;NC&#125;&quot; # 强制卸载 log &quot;尝试强制卸载...&quot; umount -l &quot;$MOUNT_POINT&quot; &amp;&amp; log &quot;$&#123;GREEN&#125;强制卸载成功$&#123;NC&#125;&quot; fi else log &quot;$&#123;BLUE&#125;硬盘未挂载$&#123;NC&#125;&quot; fi&#125;# 切换到 host 模式switch_to_host() &#123; local current=$(get_current_mode) log &quot;$&#123;BLUE&#125;当前模式: $current -&gt; 目标模式: host$&#123;NC&#125;&quot; if [ &quot;$current&quot; = &quot;host&quot; ]; then log &quot;$&#123;YELLOW&#125;已经是 host 模式$&#123;NC&#125;&quot; else # 先卸载可能加载的 gadget 驱动 modprobe -r g_serial g_ether g_mass_storage usb_f_* libcomposite 2&gt;/dev/null # 切换到 host log &quot;$&#123;YELLOW&#125;切换到 host 模式...$&#123;NC&#125;&quot; echo &quot;host&quot; &gt; &quot;$USB_ROLE_FILE&quot; sleep 3 # 重新加载存储驱动 modprobe usb-storage modprobe uas # 重新扫描 SCSI 总线 echo &quot;- - -&quot; &gt; /sys/class/scsi_host/host0/scan 2&gt;/dev/null echo &quot;- - -&quot; &gt; /sys/class/scsi_host/host1/scan 2&gt;/dev/null sleep 2 local new=$(get_current_mode) if [ &quot;$new&quot; = &quot;host&quot; ]; then log &quot;$&#123;GREEN&#125;切换到 host 模式成功$&#123;NC&#125;&quot; else log &quot;$&#123;RED&#125;切换到 host 模式失败，当前模式: $new$&#123;NC&#125;&quot; return 1 fi fi # 挂载硬盘 mount_hdd # 显示最终状态 show_status&#125;# 切换到 gadget 模式switch_to_gadget() &#123; local current=$(get_current_mode) log &quot;$&#123;BLUE&#125;当前模式: $current -&gt; 目标模式: gadget$&#123;NC&#125;&quot; # 先卸载硬盘 umount_hdd if [ &quot;$current&quot; = &quot;gadget&quot; ]; then log &quot;$&#123;YELLOW&#125;已经是 gadget 模式$&#123;NC&#125;&quot; else # 卸载存储驱动 modprobe -r usb-storage uas 2&gt;/dev/null # 切换到 gadget log &quot;$&#123;YELLOW&#125;切换到 gadget 模式...$&#123;NC&#125;&quot; echo &quot;gadget&quot; &gt; &quot;$USB_ROLE_FILE&quot; sleep 2 local new=$(get_current_mode) if [ &quot;$new&quot; = &quot;gadget&quot; ]; then log &quot;$&#123;GREEN&#125;切换到 gadget 模式成功$&#123;NC&#125;&quot; # 加载常用的 gadget 功能 modprobe g_serial 2&gt;/dev/null # USB 串口 modprobe g_ether 2&gt;/dev/null # USB 网络 else log &quot;$&#123;RED&#125;切换到 gadget 模式失败，当前模式: $new$&#123;NC&#125;&quot; # 尝试强制切换 log &quot;尝试强制切换...&quot; modprobe -r ci_hdrc 2&gt;/dev/null modprobe ci_hdrc echo &quot;gadget&quot; &gt; &quot;$USB_ROLE_FILE&quot; 2&gt;/dev/null fi fi # 显示最终状态 show_status&#125;# 显示状态show_status() &#123; echo -e &quot;
$&#123;BLUE&#125;=== USB 状态 ===$&#123;NC&#125;&quot; # USB 角色 local role=$(get_current_mode) echo -e &quot;USB 模式: $&#123;GREEN&#125;$role$&#123;NC&#125;&quot; # 硬盘设备 local hdd=$(lsblk -o NAME,SIZE,MODEL | grep -E &quot;sd[a-z]&quot; | head -3) if [ -n &quot;$hdd&quot; ]; then echo -e &quot;
$&#123;BLUE&#125;硬盘设备:$&#123;NC&#125;&quot; echo &quot;$hdd&quot; fi # 挂载状态 if is_mounted; then echo -e &quot;
$&#123;GREEN&#125;硬盘已挂载到 $MOUNT_POINT$&#123;NC&#125;&quot; df -h &quot;$MOUNT_POINT&quot; | tail -1 else echo -e &quot;
$&#123;YELLOW&#125;硬盘未挂载$&#123;NC&#125;&quot; fi # USB 控制器信息 if [ -d &quot;/sys/kernel/debug/usb/ci_hdrc.0&quot; ]; then echo -e &quot;
$&#123;BLUE&#125;USB 控制器:$&#123;NC&#125;&quot; ls /sys/kernel/debug/usb/ci_hdrc.0/ 2&gt;/dev/null | head -5 fi&#125;# 主函数main() &#123; check_root case &quot;$1&quot; in host) switch_to_host ;; gadget) switch_to_gadget ;; status) show_status ;; *) show_usage ;; esac&#125;# 执行主函数main &quot;$@&quot;EOF 🎯 使用方式 1234567891011# 给脚本添加执行权限chmod +x usb_switch.sh# 切换到 host 模式（接硬盘）并自动挂载sudo ./usb_switch.sh host# 切换到 gadget 模式（接电脑）并自动卸载sudo ./usb_switch.sh gadget# 查看当前状态sudo ./usb_switch.sh status 🚀 安装到系统路径（方便使用） 123456789101112131415161718192021# 复制到系统路径sudo cp usb_switch.sh /usr/local/bin/usb-switch# 给所有人执行权限sudo chmod +x /usr/local/bin/usb-switch# 现在可以直接运行了# 1. 切换到 host 模式（接硬盘）并自动挂载sudo usb-switch host# 2. 切换到 gadget 模式（接电脑）并自动卸载sudo usb-switch gadget# 3. 查看当前状态sudo usb-switch status# 4. 只挂载硬盘（不切换模式）- 如果硬盘没挂上时用sudo usb-switch mount# 5. 只卸载硬盘（不切换模式）- 想手动卸载时用sudo usb-switch umount 📋 脚本功能说明 这个脚本会自动： 切换模式时： 检查当前模式 卸载/加载必要的驱动 执行模式切换 host 模式下： 自动扫描并识别硬盘 自动挂载到 /mnt/nas 设置适当的权限 gadget 模式下： 自动卸载硬盘 加载常用的 gadget 功能（串口、网络） 状态显示： 显示当前 USB 模式 显示硬盘设备信息 显示挂载状态 12# 查看挂载硬盘lsblk
